sub_queries.sql:
SELECT Composition, Composer
FROM T9
WHERE Date LIKE '1955%' OR Date LIKE '1964%';

SELECT Title, Role, Year 
FROM T2 
WHERE LOWER(Title) LIKE LOWER('%weird al%') OR LOWER(Notes) LIKE LOWER('%weird al%');

SELECT MIN(CAST(Admissions AS REAL)) AS Min_Admissions, MAX(CAST(Admissions AS REAL)) AS Max_Admissions
FROM T8
WHERE Admissions NOT LIKE 'N/A' AND Admissions GLOB '[0-9]*';

SELECT Revenue, Admissions 
FROM T8 
WHERE Production_country IN ('France', 'Germany', 'India');

SELECT Revenue, Admissions
FROM T10
WHERE Title IN (
    "The Bridge on the River Kwai", 
    "Mother India"
);

SELECT Role 
FROM T1 
WHERE Title LIKE '%UHF%' OR Title LIKE '%The Naked Gun%' OR Title LIKE '%Tapeheads%';

SELECT DISTINCT Composition 
FROM T9 
WHERE (Date LIKE '1955%' OR Date LIKE '1964%');

SELECT Composition, Date
FROM T9
WHERE LOWER(Composer) LIKE '%weird%' OR LOWER(Composer) LIKE '%al%';

SELECT Year, Title, Role 
FROM T1 
WHERE Role IS NOT NULL;
